function isValidRefName(refName) {
  if (!/^[a-zA-Z0-9-._~]/.test(refName)) return false;
  if (refName.length > 63) return false;
  if (refName.includes('\x00')) return false;
  if (refName.startsWith('g.')) return false;
  return true;
}

