// Solution
class Solution:
  def isValidRefName(self, refName: str) -> bool:
    if not refName.replace('-', '', 1).replace('_', '', 1).replace('~', '', 1).isalnum():
      return False
    if len(refName) > 63:
      return False
    if '\x00' in refName:
      return False
    if refName.startswith('g.'): return False
    return True
